class Solution:
    def recoverBits(self, bitmask: str, n: int) -> str:
        result = []
        for i in range(n):
            if bitmask[i] == '1':
                result.append(1)
            else:
                if result and result[-1] == 1:
                    result.append(1)
        return ''.join(map(str, result))
